arguments.content:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Listing Job Object",
  "description": "Defines the unified listing_job object, which serves as the central task format for all Agents within this workspace. All Agent communication, state management, and task progression will revolve around this object.",
  "type": "object",
  "properties": {
    "job_id": {
      "type": "string",
      "description": "Unique identifier for the listing job.",
      "examples": ["LC-20260320-0001"]
    },
    "product_id": {
      "type": "string",
      "description": "Identifier for the product associated with this listing job.",
      "examples": ["SKU-001"]
    },
    "marketplace": {
      "type": "string",
      "description": "The target marketplace (e.g., \"Amazon US\", \"Amazon UK\").",
      "examples": ["Amazon US"]
    },
    "category": {
      "type": "string",
      "description": "The product category.",
      "examples": ["Pet Supplies"]
    },
    "brand": {
      "type": "string",
      "description": "The brand of the product.",
      "examples": ["OpenClaw AI"]
    },
    "language": {
      "type": "string",
      "description": "The target language for the listing (e.g., \"en-US\", \"zh-CN\").",
      "examples": ["en-US"]
    },
    "goal": {
      "type": "string",
      "description": "The objective of the job (e.g., \"generate_new_listing\", \"optimize_existing_listing\").",
      "examples": ["generate_new_listing"]
    },
    "inputs": {
      "type": "object",
      "description": "Contains all raw input data required for the listing generation.",
      "properties": {
        "product_brief": {
          "type": "object",
          "description": "Detailed information about the product.",
          "additionalProperties": true
        },
        "competitor_asins": {
          "type": "array",
          "description": "A list of competitor ASINs for analysis.",
          "items": {
            "type": "string"
          },
          "examples": [[]]
        },
        "keyword_seed": {
          "type": "array",
          "description": "Initial keywords or seed phrases.",
          "items": {
            "type": "string"
          },
          "examples": [[]]
        },
        "compliance_rules": {
          "type": "array",
          "description": "Any regulatory or platform-specific compliance rules.",
          "items": {
            "type": "string"
          },
          "examples": [[]]
        },
        "brand_guidelines": {
          "type": "object",
          "description": "Brand-specific tone, style, and messaging guidelines.",
          "additionalProperties": true
        }
      },
      "required": [
        "product_brief",
        "competitor_asins",
        "keyword_seed",
        "compliance_rules",
        "brand_guidelines"
      ]
    },
    "status": {
      "type": "string",
      "description": "Current status of the job (e.g., \"created\", \"data_gathering\", \"analysis\", \"generation\", \"completed\", \"failed\").",
      "examples": ["created"],
      "enum": [
        "CREATED",
        "INPUT_VALIDATED",
        "DATA_COLLECTION_PENDING",
        "DATA_COLLECTION_DONE",
        "DATA_ANALYSIS_PENDING",
        "DATA_ANALYSIS_DONE",
        "OUTPUT_GENERATION_PENDING",
        "OUTPUT_DRAFT_DONE",
        "QUALITY_REVIEW_PENDING",
        "QUALITY_APPROVED",
        "LEARNING_FEEDBACK_PENDING",
        "CLOSED",
        "NEED_REVISION",
        "RETRYING",
        "FAILED"
      ]
    },
    "current_stage": {
      "type": "string",
      "description": "The current stage of processing within the orchestration.",
      "examples": ["orchestration"]
    },
    "artifacts": {
      "type": "object",
      "description": "Stores intermediate and final outputs generated by various Agents.",
      "additionalProperties": true
    },
    "messages": {
      "type": "array",
      "description": "A log of messages or communication related to the job.",
      "items": {
        "type": "object"
      },
      "examples": [[]]
    },
    "scores": {
      "type": "object",
      "description": "Evaluation scores or metrics for the generated listing.",
      "additionalProperties": true
    },
    "audit_log": {
      "type": "array",
      "description": "A chronological record of actions and decisions made during the job\'s lifecycle.",
      "items": {
        "type": "object"
      },
      "examples": [[]]
    }
  },
  "required": [
    "job_id",
    "product_id",
    "marketplace",
    "category",
    "brand",
    "language",
    "goal",
    "inputs",
    "status",
    "current_stage",
    "artifacts",
    "messages",
    "scores",
    "audit_log"
  ]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Agent Message Protocol",
  "description": "Defines the unified message format for inter-Agent communication within the Listing Agent ecosystem. All Agents will adhere to this protocol for sending and receiving messages, ensuring seamless collaboration across independent workspaces.",
  "type": "object",
  "properties": {
    "message_id": {
      "type": "string",
      "description": "Unique identifier for the message.",
      "examples": ["msg-001"]
    },
    "job_id": {
      "type": "string",
      "description": "The `job_id` from the `listing_job` object, linking the message to a specific task.",
      "examples": ["LC-20260320-0001"]
    },
    "from_agent": {
      "type": "string",
      "description": "The identifier of the Agent sending the message.",
      "examples": ["listing_master"]
    },
    "to_agent": {
      "type": "string",
      "description": "The identifier of the Agent intended to receive the message.",
      "examples": ["listing_data_collector"]
    },
    "message_type": {
      "type": "string",
      "description": "Defines the purpose or nature of the message.",
      "enum": [
        "task_request",
        "task_response",
        "status_update",
        "revision_request",
        "error_report",
        "learning_feedback",
        "quality_gate_result"
      ],
      "examples": ["task_request"]
    },
    "task_name": {
      "type": "string",
      "description": "(Optional) The specific task or sub-task being referenced by the message.",
      "examples": ["collect_competitor_data"]
    },
    "payload": {
      "type": "object",
      "description": "Contains the actual data or content of the message. Its structure will vary depending on the `message_type`.",
      "additionalProperties": true
    },
    "timestamp": {
      "type": "string",
      "format": "date-time",
      "description": "UTC timestamp of when the message was created.",
      "examples": ["2026-03-20T10:00:00Z"]
    },
    "status": {
      "type": "string",
      "description": "Current status of the message (e.g., \"pending\", \"sent\", \"received\", \"processed\", \"error\").",
      "examples": ["pending"],
      "enum": ["pending", "sent", "received", "processed", "error"]
    }
  },
  "required": [
    "message_id",
    "job_id",
    "from_agent",
    "to_agent",
    "message_type",
    "payload",
    "timestamp",
    "status"
  ]
}

