from typing import List, Dict, Any, Optional
from pydantic import BaseModel
from openclaw_ai_amz_listing.shared.models.enums import JobStatus

class ProductBrief(BaseModel):
    product_name: Optional[str] = None
    features: Optional[List[str]] = None
    target_users: Optional[List[str]] = None
    # Add other fields as needed based on specific product brief requirements
    class Config:
        extra = "allow"

class ListingJobInputs(BaseModel):
    product_brief: ProductBrief = {}
    competitor_asins: List[str] = []
    keyword_seed: List[str] = []
    brand_guidelines: Dict[str, Any] = {}
    compliance_rules: List[str] = []

class ArtifactPaths(BaseModel):
    collection_output_path: Optional[str] = None
    analysis_output_path: Optional[str] = None
    listing_output_path: Optional[str] = None
    learning_output_path: Optional[str] = None

class ListingJob(BaseModel):
    job_id: str
    goal: str
    marketplace: str
    category: str
    brand: str
    language: str
    status: JobStatus # Use the Enum for status
    current_stage: str
    inputs: ListingJobInputs
    artifacts: ArtifactPaths = {}
    scores: Dict[str, Any] = {}
    messages: List[str] = []
    audit_log: List[Dict[str, Any]] = []

    class Config:
        use_enum_values = True
        json_encoders = {
            JobStatus: lambda v: v.value
        }

